import { Link } from "react-router-dom";

function Landing() {
  return (
    <div style={{ textAlign: "center", marginTop: "100px" }}>
      <h1>Doctor-AI 🩺</h1>
      <p>Your intelligent AI medical assistant</p>

      <Link to="/login">
        <button>Login</button>
      </Link>

      <Link to="/signup">
        <button style={{ marginLeft: "10px" }}>Signup</button>
      </Link>
    </div>
  );
}

export default Landing;
